// EP-25: greedy residue selection to maximize oscillation in log density.
{
  const rng = makeRng(20260304 ^ 25);
  const maxX = 1 << 16; // 65536
  const X1 = 1 << 12;
  const X2 = 1 << 16;
  const weights = new Float64Array(maxX + 1);
  for (let n = 1; n <= maxX; n += 1) weights[n] = 1 / n;
  const excluded = new Uint8Array(maxX + 1);

  function muX(X) {
    let s = 0;
    for (let n = 1; n <= X; n += 1) if (!excluded[n]) s += weights[n];
    return s / Math.log(X);
  }

  const moduli = [];
  const residues = [];
  const muTrack = [];
  const candidates = [];
  for (let n = 60; n <= 200; n += 1) candidates.push(n);
  shuffle(candidates, rng);

  for (let idx = 0; idx < 40; idx += 1) {
    const n = candidates[idx];
    let best = { res: 0, diff: -1, deltaX1: 0, deltaX2: 0 };
    const samples = 16;
    for (let s = 0; s < samples; s += 1) {
      const a = Math.floor(rng() * n);
      let delta1 = 0;
      let delta2 = 0;
      const start = n + ((a - n) % n + n) % n;
      for (let x = start; x <= maxX; x += n) {
        if (excluded[x]) continue;
        if (x <= X1) delta1 += weights[x];
        if (x <= X2) delta2 += weights[x];
      }
      const mu1 = (muX(X1) - delta1 / Math.log(X1));
      const mu2 = (muX(X2) - delta2 / Math.log(X2));
      const diff = Math.abs(mu1 - mu2);
      if (diff > best.diff) best = { res: a, diff, deltaX1: delta1, deltaX2: delta2 };
    }

    // Apply the best residue.
    const a = best.res;
    const start = n + ((a - n) % n + n) % n;
    for (let x = start; x <= maxX; x += n) excluded[x] = 1;

    moduli.push(n);
    residues.push(a);
    muTrack.push({
      n,
      a,
      mu_X1: Number(muX(X1).toPrecision(8)),
      mu_X2: Number(muX(X2).toPrecision(8)),
      diff: Number(best.diff.toPrecision(6)),
    });
  }

  const grid = [];
  for (let k = 10; k <= 16; k += 1) {
    const X = 1 << k;
    grid.push({ X, mu: Number(muX(X).toPrecision(8)) });
  }

  out.results.ep25 = {
    description: 'Greedy residue selection to amplify oscillation in mu_X(A) over X=2^12 and 2^16.',
    moduli_count: moduli.length,
    moduli: moduli.slice(0, 12),
    residues: residues.slice(0, 12),
    mu_track_tail: muTrack.slice(-6),
    mu_grid: grid,
  };
}
